<template>
  <el-dialog v-bind="$attrs" :visible.sync="dialogVisible" class="info-tip-modal-wrapper">
    <div class="top-info">請複製下方信息給商戶，以登錄商戶後台繼續操作。</div>
    <div class="tip-item">
      <span class="title">地址：</span>
      <span>{{ address }}</span>
    </div>
    <div class="tip-item">
      <span class="title">帳號：</span>
      <span>{{ username }}</span>
    </div>
    <div class="tip-item">
      <span class="title">密碼：</span>
      <span class="password">{{ password }}</span>
    </div>
    <span slot="footer" class="dialog-footer">
      <el-button type="primary" @click="copyInfo">複製登錄信息</el-button>
    </span>
  </el-dialog>
</template>

<script>
export default {
  props: {
    visible: {
      type: Boolean,
      require: true
    },
    password: String,
    username: String
  },
  data() {
    return {
      address: ''
    }
  },
  computed: {
    dialogVisible: {
      get() {
        return this.visible
      },
      set() {
        this.$emit('update:visible', false)
      }
    }
  },
  mounted() {
    this.getAddress()
  },
  methods: {
    getAddress() {
      let host = location.host
      this.address = `${host}/merchant/login`
    },
    copyInfo() {
      let textarea = document.createElement('textarea')
      textarea.value = `地址：${this.address}\n帳號：${this.username}\n密碼：${this.password}`
      textarea.readOnly = 'readOnly'
      document.body.appendChild(textarea)
      textarea.select()
      let result = document.execCommand('copy')
      if (result) {
        this.$message({
          message: '複製信息成功',
          type: 'success'
        })
      }
      textarea.remove()
    }
  }
}
</script>

<style lang="scss">
.info-tip-modal-wrapper {
  .top-info {
    border: 1px solid #ebeef5;
    padding: 3px 5px;
    border-radius: 6px;
    margin-bottom: 10px;
  }
  .tip-item {
    line-height: 40px;
  }
  .el-dialog__footer {
    text-align: center;
  }
  .password {
    margin-right: 20px;
  }
}
</style>
